# Vérifier la structure complète du .claude.json
cat /home/gilles/.claude.json | python3 -c "
import json, sys
data = json.load(sys.stdin)

# Vérifier user-level mcpServers
if 'mcpServers' in data:
    print('USER-LEVEL mcpServers:', json.dumps(data['mcpServers'], indent=2))
else:
    print('PAS de mcpServers au niveau user')

# Vérifier project-level
if 'projects' in data:
    for proj, conf in data['projects'].items():
        if 'mcpServers' in conf:
            print(f'PROJECT [{proj}] mcpServers:', json.dumps(conf['mcpServers'], indent=2))
"

